import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as d,c,a as t,e as a,b as r,w as i,d as h}from"./app-0a44add1.js";const l={},o=h('<h2 id="meshdistancematerial" tabindex="-1"><a class="header-anchor" href="#meshdistancematerial" aria-hidden="true">#</a> MeshDistanceMaterial</h2><p>MeshDistanceMaterial 在内部用于使用PointLight来实现阴影映射。 也可以用于通过将MeshDistanceMaterial实例指定给Object3D.customDistanceMaterial，来自定义物体阴影投射。 下列示例演示了这一方法，以确保物体的透明部分不投射阴影。</p><h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="parameters-object" tabindex="-1"><a class="header-anchor" href="#parameters-object" aria-hidden="true">#</a> parameters : Object</h3><p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性)</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2>',6),p=h('<h3 id="alphamap-texture" tabindex="-1"><a class="header-anchor" href="#alphamap-texture" aria-hidden="true">#</a> .alphaMap : Texture</h3><p>alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。</p><p>仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。</p><h3 id="displacementmap-texture" tabindex="-1"><a class="header-anchor" href="#displacementmap-texture" aria-hidden="true">#</a> .displacementMap : Texture</h3><p>位移贴图会影响网格顶点的位置，与仅影响材质的光照和阴影的其他贴图不同，移位的顶点可以投射阴影，阻挡其他对象，以及充当真实的几何体。 位移纹理是指：网格的所有顶点被映射为图像中每个像素的值（白色是最高的），并且被重定位。</p><h3 id="displacementscale-float" tabindex="-1"><a class="header-anchor" href="#displacementscale-float" aria-hidden="true">#</a> .displacementScale : Float</h3><p>位移贴图对网格的影响程度（黑色是无位移，白色是最大位移）。如果没有设置位移贴图，则不会应用此值。默认值为1。</p><h3 id="displacementbias-float" tabindex="-1"><a class="header-anchor" href="#displacementbias-float" aria-hidden="true">#</a> .displacementBias : Float</h3><p>位移贴图在网格顶点上的偏移量。如果没有设置位移贴图，则不会应用此值。默认值为0。</p><h3 id="fardistance-float" tabindex="-1"><a class="header-anchor" href="#fardistance-float" aria-hidden="true">#</a> .farDistance : Float</h3><p>点光源的内部阴影相机的远值。</p><h3 id="map-texture" tabindex="-1"><a class="header-anchor" href="#map-texture" aria-hidden="true">#</a> .map : Texture</h3><p>颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。</p><h3 id="neardistance-float" tabindex="-1"><a class="header-anchor" href="#neardistance-float" aria-hidden="true">#</a> .nearDistance : Float</h3><p>点光源的内部阴影相机的近值。</p><h3 id="referenceposition-vector3" tabindex="-1"><a class="header-anchor" href="#referenceposition-vector3" aria-hidden="true">#</a> .referencePosition : Vector3</h3><p>光点在世界空间中的位置。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2>',18);function m(u,f){const e=s("RouterLink");return d(),c("div",null,[o,t("p",null,[a("共有属性请参见其基类"),r(e,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:i(()=>[a("Material")]),_:1})]),p,t("p",null,[a("共有方法请参见其基类"),r(e,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:i(()=>[a("Material")]),_:1})])])}const _=n(l,[["render",m],["__file","MeshDistanceMaterial.html.vue"]]);export{_ as default};
